mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM sys_dept_tenant_scope
    WHERE dept_id = #{deptId}
      AND tenant_id = #{tenantId}
      AND status = 1
)

SELECT audit.audit_id, audit.tenant_id, audit.operation_type, audit.payload_json::text AS payload_json, actor_user.account_id AS operator_account_id, audit.operator_user_id, COALESCE(NULLIF(actor_user.nick_name, ''), actor_user.user_name) AS operator_name, ( SELECT STRING_AGG(role.role_name, '、' ORDER BY role.role_id) FROM sys_user_role user_role JOIN sys_role role ON role.role_id = user_role.role_id WHERE user_role.user_id = audit.operator_user_id AND role.status = '0' ) AS operator_role_name, audit.create_time FROM t_tenant_community_settings_audit audit LEFT JOIN sys_user actor_user ON actor_user.user_id = audit.operator_user_id WHERE audit.tenant_id = #{tenantId} AND audit.operation_type IN
#{operationType}
ORDER BY audit.create_time DESC, audit.audit_id DESC LIMIT #{limit}

INSERT INTO t_tenant_statistics_snapshot (
    tenant_id, statistics_version, total_area, total_owner_count, item_count,
    source_type, source_ref_id, audit_hash, created_by
)
VALUES (
    #{tenantId}, #{statisticsVersion}, #{totalArea}, #{ownerCount}, #{itemCount},
    #{sourceType}, #{sourceRefId}, #{auditHash}, #{operatorUserId}
)
RETURNING snapshot_id

INSERT INTO t_tenant_denominator_review_request (
    tenant_id, requested_total_area, requested_owner_count, requested_unit_count,
    reason, requested_by
)
VALUES (
    #{tenantId}, #{requestedTotalArea}, #{requestedOwnerCount}, #{requestedUnitCount},
    #{reason}, #{requestedBy}
)
RETURNING request_id

mapper.insert:
INSERT INTO t_tenant_community_settings_audit (
    tenant_id, operation_type, payload_json, operator_user_id
)
VALUES (
    #{tenantId}, #{operationType}, CAST(#{payloadJson} AS JSONB), #{operatorUserId}
)
